head.script:
// 전역변수
scwin.login = $c.data.getMemInfo();
scwin.privAdmin = scwin.login.privAdmin;
scwin.adminYn = scwin.login.sysAdminYn;
scwin.vUserHomeClsCd = scwin.login.userHomeClsCd;
scwin.vLoginCoCd = scwin.login.coCd;
scwin.vLoginCoClsCd = scwin.login.coClsCd;
scwin.vEmpNo = $c.data.getMemInfo("empNo");// 사용자 아이디
scwin.ParamCloseYm = "";
scwin.ParamAcctDeptcd = "";
scwin.ParamAcctDeptNm = "";  


scwin.onpageload = function() {

};

scwin.onUdcCompleted = async function() {

    // f_createHeader();	
    ica_closeYm.setValue(WebSquare.date.getCurrentServerDate().substring(0,6));	    
    ed_rate.setValue("4");
    acb_unit.setSelectedIndex(0); 		
    $c.gus.cfDisableObjects([btn_create]);		
    //물류운영팀 신상윤 과장만 생성버튼 권한
    if( scwin.vEmpNo == "072924" || scwin.adminYn == "1"){
        $c.gus.cfEnableObjects([btn_create]); 					
    }else{
        $c.gus.cfDisableObjects([btn_create]);
    }	
};

