//-------------------------------------------------------------------------
// 엑셀 파일 다운로드
//-------------------------------------------------------------------------
scwin.f_GridToExcel = async function(gr_groupCode, gridName) {
    if ( ds_master.getRowConut <= 0)
    {
        await $c.gus.cfAlertMsg("자산현황이 존재하지않습니다.");
        return false;
    }

    var options = {
            fileName: "지사별자산현황",
            sheetName: "지사별자산현황"
        }   

    $c.data.downloadGridViewExcel(gr_master, options);
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    if ( !await $c.gus.cfValidate([ica_closeYm]) ) {
        return;
    }

    if( ed_rate.getValue() == "") {
        await $c.gus.cfAlertMsg("투자금리를 입력 후 조회가능합니다");
        return;		  	    
    }  	  

    scwin.f_Change();  	

    dma_search.set("closeYm", ica_closeYm.getValue());
    dma_search.set("rate", ed_rate.getValue());
    dma_search.set("unit", acb_unit.getValue());

    $c.sbm.execute(sbm_retrieve);
}

//그리드 월 세팅
scwin.f_Change = function() {
    var closeMm = ica_closeYm.getValue().substring(4,6);	

    gr_master.setHeaderValue("header1", closeMm + '월');
    gr_master.setHeaderValue("header2", closeMm + '월 누계');
    gr_master.setHeaderValue("header3", closeMm + '월');
    gr_master.setHeaderValue("header4", closeMm + '월 누계');
    gr_master.setHeaderValue("header5", closeMm + '월');
    gr_master.setHeaderValue("header6", closeMm + '월 누계');
    gr_master.setHeaderValue("header7", closeMm + '월');
    gr_master.setHeaderValue("header8", closeMm + '월 누계');
    gr_master.setHeaderValue("header9", closeMm + '월');
    gr_master.setHeaderValue("header10", closeMm + '월 누계');
    gr_master.setHeaderValue("header11", closeMm + '월');
    gr_master.setHeaderValue("header12", closeMm + '월 누계');
    gr_master.setHeaderValue("header13", closeMm + '월');
    gr_master.setHeaderValue("header14", closeMm + '월 누계');
    gr_master.setHeaderValue("header15", closeMm + '월');
    gr_master.setHeaderValue("header16", closeMm + '월 누계');
    gr_master.setHeaderValue("header17", closeMm + '월');
    gr_master.setHeaderValue("header18", closeMm + '월 누계');
    gr_master.setHeaderValue("header19", closeMm + '월');
    gr_master.setHeaderValue("header20", closeMm + '월 누계');					
}

//-------------------------------------------------------------------------
//  그리드 클릭
//-------------------------------------------------------------------------
scwin.f_Popup = async function(){

    // var parObject = new Object();
    // parObject.pCloseYm = ParamCloseYm;
    // parObject.pAcctDeptCd = ParamAcctDeptcd;      
    // parObject.pAcctDeptNm = ParamAcctDeptNm;      		

    // var style = "center:yes; dialogwidth:900px; dialogheight:500px; scroll:no; resizable:yes; status:yes;";
    // var strPath = "fi_301_02_10p.jsp";

    // var returnValue = window.showModalDialog(strPath, parObject ,style ) ;

    let data = {
        pCloseYm: scwin.ParamCloseYm,
        pAcctDeptCd: scwin.ParamAcctDeptcd,
        pAcctDeptNm: scwin.ParamAcctDeptNm
    }
    let returnValue;

    const options = {
        id: "fi_301_02_10p",
        type: "popup",
        modal: true,
        type:"browserPopup",
        popupName: "클래스별 자산현황",
