        height: "700"
    };

    returnValue = await $c.win.openPopup("/ui/ac/fi/fixedaset/fi_301_02_10p.xml", options, data);

}

//-------------------------------------------------------------------------
// 생성
//-------------------------------------------------------------------------
scwin.f_Create = async function(){
    if(await $c.win.confirm(MSG_CM_CRM_002) == true){

        dma_search.set("closeYm", ica_closeYm.getValue());
        dma_search.set("rate", ed_rate.getValue());
        dma_search.set("unit", acb_unit.getValue());
        $c.sbm.execute(sbm_create);
    }	   
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function(){

    if ( acb_unit.getValue() != "1" ) {
        await $c.gus.cfAlertMsg('단위가 원 일때만 저장가능합니다');		
        return;
    }		

    if(await $c.win.confirm(MSG_CM_CRM_001) == true){	
        $c.sbm.execute(sbm_retrieve);
    }		  
}


scwin.ds_master_ondataload = async function () {
    var rowCnt = ds_master.getRowCount();
    if( rowCnt == 0 ){
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
	}

	var planTotalAset = null;			//당해년 계획 전사 취득가액
	var planNonAset1 = null;			//당해년 계획 비상각자산(토지)
	var planNonAset2 = null;			//당해년 계획 비상각자산(건설중인자산)
	var planNonAset3 = null;			//당해년 계획 비상각자산(무형자산)		
	var toralAset = null;				//당해년 실적 전사 취득가액
	var nonAset1 = null;				//당해년 실적 비상각자산(토지)
	var nonAset2 = null;				//당해년 실적 비상각자산(건설중인자산)
	var nonAset3 = null;				//당해년 실적 비상각자산(무형자산)
	var bfToralAset = null;				//전년 실적 전사 취득가액
	var bfNonAset1 = null;				//전년 실적 비상각자산(토지)
	var bfNonAset2 = null;				//전년 실적 비상각자산(건설중인자산)
	var bfNonAset3 = null;				//전년 실적 비상각자산(무형자산)
	var planTotalDeprAmt = null;		//당해년 계획 감가상각 누계(전사)
	var totalDeprAmt = null;			//당해년 실적 감가상각 누계(전사)
	var bfTotalDeprAmt = null;			//전년 계획 감가상각 누계(전사)
	var planRestAset = null; 			//감가 잔존자산액(당해년 계획)
	var restAset = null;				//감가 잔존자산액(당해년 실적)
	var bfRestAset = null;				//감가 잔존자산액(전년 실적)
	var planYyRestAset = null; 			//감가 잔존자산액(당해년 계획)
	var restYyAset = null;				//감가 잔존자산액(당해년 실적)
	var bfYyRestAset = null;			//감가 잔존자산액(전년 실적)	

	var month = ica_closeYm.getValue().substring(4,6);

    for(var i=0; i<rowCnt; i++) {   	  

		if (ds_master.getCellData(i,"acctDeptCd")=="00011"||ds_master.getCellData(i,"acctDeptCd")=="00211"||ds_master.getCellData(i,"acctDeptCd")=="00241"){			
		 	ds_master.removeRow(i); //본사 아래 부서 그리드 숨기기
            i = i-1;
            continue;
		}
		if( (ds_master.getCellData(i, "asetGbn") == '1') && (ds_master.getCellData(i, "acctDeptCd") == '00134') ) {			
            ds_master.removeRow(i);  //지사 중 물류정비합계 그리드 숨기기
            i = i-1;
            continue;

		}
		if( (ds_master.getCellData(i, "asetGbn") == '1') && (ds_master.getCellData(i, "acctDeptCd") == '00000') ) {			
    		planTotalAset = Number(ds_master.getCellData(i, "planBookAmt"));														    	
    		toralAset = Number(ds_master.getCellData(i, "bookAmt"));	    		
    		bfToralAset = Number(ds_master.getCellData(i, "bfBookAmt"));    	
			planTotalDeprAmt = Number(ds_master.getCellData(i, "planDeprCumAmt"));														    	
    		totalDeprAmt = Number(ds_master.getCellData(i, "deprCumAmt"));	    		
    		bfTotalDeprAmt = Number(ds_master.getCellData(i, "bfDeprCumAmt"));    	    			
		}	
		if ( ds_master.getCellData(i, "asetGbn") == '2' ) {				
	    	planNonAset1 = Number(ds_master.getCellData(i, "planBookAmt"));	
	    	nonAset1 = Number(ds_master.getCellData(i, "bookAmt"));		    	
	    	bfNonAset1 = Number(ds_master.getCellData(i, "bfBookAmt"));		    		    	
		}
		if ( ds_master.getCellData(i, "asetGbn") == '3' ) {							
	    	planNonAset2 = Number(ds_master.getCellData(i, "planBookAmt"));	
	    	nonAset2 = Number(ds_master.getCellData(i, "bookAmt"));		    	
	    	bfNonAset2 = Number(ds_master.getCellData(i, "bfBookAmt"));		    		    	
		}	
		if ( ds_master.getCellData(i, "asetGbn") == '4' ) {			
	    	planNonAset3 = Number(ds_master.getCellData(i, "planBookAmt"));	
	    	nonAset3 = Number(ds_master.getCellData(i, "bookAmt"));					
	    	bfNonAset3 = Number(ds_master.getCellData(i, "bfBookAmt"));		    		    													    	
		}										
		if ( ds_master.getCellData(i, "asetGbn") == '5' ) {		
			ds_master.setCellData(i, "planBookAmt", (planTotalAset - planNonAset1 - planNonAset2 - planNonAset3));
			ds_master.setCellData(i, "bookAmt",(toralAset - nonAset1 - nonAset2 - nonAset3));
			ds_master.setCellData(i, "bfBookAmt",(bfToralAset - bfNonAset1 - bfNonAset2 - bfNonAset3));						
			planRestAset = Number(ds_master.getCellData(i, "planBookAmt")); 			//감가 잔존자산액(당해년 계획)
			restAset = Number(ds_master.getCellData(i, "bookAmt"));					//감가 잔존자산액(당해년 실적)
			bfRestAset = Number(ds_master.getCellData(i, "bfBookAmt"));				//감가 잔존자산액(전년 실적)	
		}		
		if ( ds_master.getCellData(i, "asetGbn") == '6' ) {			
            var planDeprCumAmt = planTotalDeprAmt / month * 12;
            var deprCumAmt = totalDeprAmt / month * 12;
            var bfDeprCumAmt = bfTotalDeprAmt / month * 12;
            if(Number.isNaN(planDeprCumAmt)){
                ds_master.setCellData(i, "planDeprCumAmt", -1);
            } else {
                ds_master.setCellData(i, "planDeprCumAmt",planDeprCumAmt);	//감가상각 잔존연수(당해년 계획)
            }

            if(Number.isNaN(deprCumAmt)){
                ds_master.setCellData(i, "deprCumAmt", -1);
            } else {
                ds_master.setCellData(i, "deprCumAmt",deprCumAmt);	//감가상각 잔존연수(당해년 계획)
            }

            if(Number.isNaN(bfDeprCumAmt)){
                ds_master.setCellData(i, "bfDeprCumAmt", -1);
            } else {
                ds_master.setCellData(i, "bfDeprCumAmt",bfDeprCumAmt);	//감가상각 잔존연수(당해년 계획)
            }
			planYyRestAset = Number(ds_master.getCellData(i, "planDeprCumAmt")); 			//연기준 감가상각액(당해년 계획)
			restYyAset = Number(ds_master.getCellData(i, "deprCumAmt"));					//연기준 감가상각액(당해년 실적)
			bfYyRestAset = Number(ds_master.getCellData(i, "bfDeprCumAmt"));				//연기준 감가상각액(전년 실적)				

		}
		if ( ds_master.getCellData(i, "asetGbn") == '7' ) {
            var planDeprCumAmt = planRestAset / planYyRestAset;
            var deprCumAmt = restAset / restYyAset;
            var bfDeprCumAmt = bfRestAset / bfYyRestAset;

            if(Number.isNaN(planDeprCumAmt)){
                ds_master.setCellData(i, "planDeprCumAmt", -1);
            } else {
                ds_master.setCellData(i, "planDeprCumAmt",planDeprCumAmt);	
            }

            if(Number.isNaN(deprCumAmt)){
                ds_master.setCellData(i, "deprCumAmt", -1);
            } else {
                ds_master.setCellData(i, "deprCumAmt",deprCumAmt);	
            }

            if(Number.isNaN(bfDeprCumAmt)){
                ds_master.setCellData(i, "bfDeprCumAmt", -1);
            } else {
                ds_master.setCellData(i, "bfDeprCumAmt",bfDeprCumAmt);	
            }
		} 
	}	

	// ds_master.ResetStatus();
};

scwin.sbm_retrieve_submiterror = function (e) {
    $c.gus.cfShowError(sbm_retrieve);
};


scwin.sbm_save_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
	scwin.f_Retrieve();
};

scwin.sbm_save_submiterror = function (e) {
    $c.gus.cfShowError(this);	
};

scwin.sbm_create_submitdone = async function (e) {
    $c.gus.cfAlertMsg(MSG_CM_INF_002);	// 성공적으로 등록하였습니다
	scwin.f_Retrieve();
};

scwin.gr_master_oncellclick = function (rowIndex, columnIndex, columnId) {
    colid = gr_master.getColumnID(columnIndex)
    if(colid == "asetGbnNm"){ // asetGbnNm
        scwin.ParamCloseYm = ica_closeYm.getValue();  		
		scwin.ParamAcctDeptcd = ds_master.getCellData(rowIndex, "acctDeptCd");  		
		scwin.ParamAcctDeptNm = ds_master.getCellData(rowIndex, "cdNm");  				

		scwin.f_Popup();		
    }
};


scwin.btn_search_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.btn_create_onclick = function (e) {
    scwin.f_Create();
};

scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {

        var count = ds_master.getRowCount();
        ed_totalRow.setValue(count);
        for(let i=0; i<count; i++){

            if(ds_master.getCellData(i, "asetGbn") == "5"){
                ds_master.setCellData(i, "asetGbnNm", "감가 잔존자산액");
            } else if (ds_master.getCellData(i, "asetGbn") == "6"){
                ds_master.setCellData(i, "asetGbnNm", "연기준 감가상각액");
            } else if (ds_master.getCellData(i, "asetGbn") == "7"){
                ds_master.setCellData(i, "asetGbnNm", "감가상각 잔존연수");
            }

            ds_master.setCellData(i, "riseAcqAmt", Number(ds_master.getCellData(i, "acqAmt")) - Number(ds_master.getCellData(i, "bfAcqAmt")));
            ds_master.setCellData(i, "riseBookAmt", Number(ds_master.getCellData(i, "bookAmt")) - Number(ds_master.getCellData(i, "bfBookAmt")));
            ds_master.setCellData(i, "riseDeprAmt", Number(ds_master.getCellData(i, "deprAmt")) - Number(ds_master.getCellData(i, "bfDeprAmt")));
            ds_master.setCellData(i, "riseDeprCumAmt", Number(ds_master.getCellData(i, "deprCumAmt")) - Number(ds_master.getCellData(i, "bfDeprCumAmt")));
            ds_master.setCellData(i, "riseInvestRate", Number(ds_master.getCellData(i, "investRate")) - Number(ds_master.getCellData(i, "bfInvestRate")));
            ds_master.setCellData(i, "riseInvestRateSum", Number(ds_master.getCellData(i, "investRateSum")) - Number(ds_master.getCellData(i, "bfInvestRateSum")));
        }

        ds_master_origin.setJSON(ds_master.getAllJSON());
    }
};

