scwin.unitFormat = function(value){

    var result;
    result = value / acb_unit.getValue();

    return $c.num.formatNumber(result);
}

scwin.acb_unit_onchange = function (info) {

    // dma_search.set("closeYm", ica_closeYm.getValue());
    // dma_search.set("rate", ed_rate.getValue());
    // dma_search.set("unit", acb_unit.getValue());

    // $c.sbm.execute(sbm_retrieve);

    var colid;
    var originData;
    for(let i=0; i<ds_master.getTotalRow(); i++){
        for(let j=0; j<gr_master.getTotalCol(); j++){
            if(gr_master.getDataType(j) == "number"){
                colid = gr_master.getColumnID(j)
                originData = Number(ds_master_origin.getCellData(i,colid));
                if(originData < 0){
                    ds_master.setCellData(i,colid,Math.ceil(Number(ds_master_origin.getCellData(i,colid)) / Number(acb_unit.getValue())))

                } else {

                    ds_master.setCellData(i,colid,Math.floor(Number(ds_master_origin.getCellData(i,colid)) / Number(acb_unit.getValue()))) ;	
                }
            }
        }
    }
};
